-- =============================================
-- Estándares de Flota (DPO Flota 1.2 R1/R3): matriz de cumplimiento
-- ítem × unidad (camiones y autoelevadores), migrada de la planilla
-- "ESTANDAR DE LA FLOTA" del CD y mantenida viva contra catalogo_vehiculos.
-- KPI estandares_conformidad (% de ítems OK sobre evaluables) con snapshot
-- mensual vía flota-kpi-cron.
-- =============================================

CREATE TABLE flota_estandar_items (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  ambito TEXT NOT NULL CHECK (ambito IN ('camion', 'autoelevador')),
  nombre TEXT NOT NULL,
  productividad TEXT,
  seguridad TEXT,
  calidad TEXT,
  orden INTEGER NOT NULL DEFAULT 0,
  activo BOOLEAN NOT NULL DEFAULT true,
  UNIQUE (ambito, nombre)
);

CREATE TABLE flota_estandar_cumplimiento (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  dominio TEXT NOT NULL,
  item_id UUID NOT NULL REFERENCES flota_estandar_items(id) ON DELETE CASCADE,
  estado TEXT NOT NULL CHECK (estado IN ('ok', 'no_ok', 'na')),
  observaciones TEXT,
  updated_by UUID REFERENCES profiles(id),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (dominio, item_id)
);

CREATE INDEX idx_flota_est_cumpl_dominio ON flota_estandar_cumplimiento(dominio);

ALTER TABLE flota_estandar_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE flota_estandar_cumplimiento ENABLE ROW LEVEL SECURITY;

CREATE POLICY "flota_est_items_read" ON flota_estandar_items
  FOR SELECT TO authenticated USING (true);
CREATE POLICY "flota_est_items_write" ON flota_estandar_items
  FOR ALL TO authenticated
  USING (EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND role IN ('admin', 'supervisor')));

CREATE POLICY "flota_est_cumpl_read" ON flota_estandar_cumplimiento
  FOR SELECT TO authenticated USING (true);
CREATE POLICY "flota_est_cumpl_insert" ON flota_estandar_cumplimiento
  FOR INSERT TO authenticated WITH CHECK (true);
CREATE POLICY "flota_est_cumpl_update" ON flota_estandar_cumplimiento
  FOR UPDATE TO authenticated
  USING (EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND role IN ('admin', 'supervisor')));

CREATE TRIGGER flota_est_cumpl_updated_at
  BEFORE UPDATE ON flota_estandar_cumplimiento
  FOR EACH ROW
  EXECUTE FUNCTION flota_plan_set_updated_at();

ON CONFLICT (kpi) DO NOTHING;

